prometheusConfig.promQL:
(
  sum by (exported_job) (
    http_server_request_duration_seconds_count{
      job="otlp",
      http_route="/actuator/health",
      http_response_status_code=~"2.*"
    }
  )
  /
  sum by (exported_job) (
    http_server_request_duration_seconds_count{
      job="otlp",
      http_route="/actuator/health"
    }
  )
) * 100

prometheusConfig.annotations:
Namespace：${labels.namespace}
Pod：${labels.pod}
内存使用率过高，当前：${labels.value}%
